example.code:
from qdrant_client.models import Filter, FieldCondition, MatchValue, Range
results = client.search( collection_name="documents", query_vector=query_embedding, query_filter=Filter( must=[ FieldCondition(key="category", match=MatchValue(value="technical")), FieldCondition(key="page", range=Range(gte=1, lte=10)), ] ), limit=10, score_threshold=0.7, with_payload=True, with_vectors=False, )
for r in results: print(f"ID: {r.id}, Score: {r.score:.3f} | {r.payload['text'][:80]}")
